export function projectYunnan(lat: number, lng: number): { x: number; y: number } {
  const { minLng, maxLng, minLat, maxLat } = YUNNAN_BOUNDS;
  const x = ((lng - minLng) / (maxLng - minLng)) * MAP_VB.w;
  const y = ((maxLat - lat) / (maxLat - minLat)) * MAP_VB.h;
  return { x, y };
}
